const incoming = msg.payload;
msg.payload = {
    deviceId: incoming.deviceId || 'ESP32_01',
    bpm: Number(incoming.bpm),
    spo2: Number(incoming.spo2),
    bodyTemp: Number(incoming.bodyTemp),
    timestamp: new Date().toISOString()
};
return msg;

msg.vitalsContext = msg.payload;
msg.payload = { deviceId: msg.vitalsContext.deviceId || 'ESP32_01' };
return msg;

msg.configContext = msg.payload || {
    minBPM: 60, maxBPM: 100, minSpO2: 95, maxSpO2: 100, minTemp: 36.0, maxTemp: 37.5
};

// Build query to fetch the last 10 historical entries sorted sequentially
msg.payload = [
    { $match: { deviceId: msg.vitalsContext.deviceId } },
    { $sort: { timestamp: -1 } },
    { $limit: 10 },
    { $sort: { timestamp: 1 } }
];
return msg;

const groqKey = env.get("GROQ_API_KEY");
const history = msg.payload || [];
const cfg = msg.configContext;
const current = msg.vitalsContext;

// Format history stack cleanly for trend parsing
const historyString = history.map(h => `[Time: ${h.timestamp}, Pulse: ${h.bpm}BPM, SpO2: ${h.spo2}%, Temp: ${h.bodyTemp}°C]`).join('\n');

msg.headers = { 
    'Authorization': 'Bearer ' + groqKey, 
    'Content-Type': 'application/json' 
};

msg.payload = {
    model: 'llama-3.1-8b-instant',
    messages: [
        { 
            role: 'system', 
            content: 'You are an advanced medical telemetry monitor analyst AI. You must evaluate the trailing timeline trend context of 10 readings against the dynamic thresholds configuration limits provided.\n\nCRITICAL OUTPUT REQUIREMENT: You MUST respond exactly in this raw structure layout with no extra conversational markdown introduction prose:\nStatus: [Normal OR Warning <parameter description detail text> OR Alert <parameter description detail text>]\nRemark: [Your clear analytical observation detail matching the exact status chosen.]'
        },
        {
            role: 'user',
            content: `Evaluate this dataset:\n\nDYNAMIC PROFILE SAFE RANGE THRESHOLDS:\n- Pulse Limits: ${cfg.minBPM} to ${cfg.maxBPM} BPM\n- Oxygen Target: Above ${cfg.minSpO2}%\n- Temperature Limits: ${cfg.minTemp} to ${cfg.maxTemp}°C\n\nTRAILING 10 HISTORICAL RECORD TIMELINE STREAM:\n${historyString}\n\nLATEST INCOMING telemetry PACKET AT CURRENT HANDSHAKE:\n- Pulse Rate: ${current.bpm} BPM\n- Blood Oxygen (SpO2): ${current.spo2}%\n- Body Temperature: ${current.bodyTemp}°C` 
        }
    ]
};

return msg;

const aiRawText = msg.payload?.choices?.[0]?.message?.content || 'Status: Warning\nRemark: Engine failure.';

let status = 'Normal';
let remark = 'All parameters are normal and no signs of any alerts.';

const statusMatch = aiRawText.match(/Status:\s*(.+)/i);
const remarkMatch = aiRawText.match(/Remark:\s*([\s\S]+)/i);

if (statusMatch) status = statusMatch[1].trim();
if (remarkMatch) remark = remarkMatch[1].trim();

// Create structured database collection tracking file format
msg.payload = {
    deviceId: msg.vitalsContext.deviceId,
    telemetryId: msg.vitalsContext._id,
    status: status,
    remark: remark,
    timestamp: new Date().toISOString()
};

return msg;

const aiDoc = msg.payload.document || msg.payload;
const status = aiDoc.status || 'Normal';

// Condition check: Route email ONLY if status explicitly registers an Emergency 'Alert'
if (status.toLowerCase().includes('alert')) {
    msg.to = "your-alert-inbox@gmail.com";
    msg.topic = "⚠️ CRITICAL SYSTEM MEDICAL ALERT: " + aiDoc.deviceId;
    msg.payload = `AI Telemetry Classification System Report:\n\n[Current Evaluation Summary Status Flag]:\n${status}\n\n[Clinical Diagnostics Review Analyst Remark]:\n${aiDoc.remark}`;
    return msg;
}

return null;
